// Helper: Get scenarios for a specific service
export function getScenariosByService(serviceId: string): TestScenario[] {
  return TEST_SCENARIOS.filter(s => s.serviceId === serviceId)
}

// Helper: Get scenarios by status
export function getScenariosByStatus(status: TestScenario['status']): TestScenario[] {
  return TEST_SCENARIOS.filter(s => s.status === status)
}

